# Create a CA policy that requires ToU acceptance before accessing all cloud apps
# Scoped to all guest users (B2B)
$caPolicy = @{
    displayName = 'Require guest ToU acceptance'
    state       = 'enabled'
    conditions  = @{
        users = @{
            includeGuestsOrExternalUsers = @{
                guestOrExternalUserTypes = 'internalGuest,b2bCollaborationGuest'
                externalTenants = @{ membershipKind = 'all' }
            }
        }
        applications = @{ includeApplications = @('All') }
        clientAppTypes = @('browser', 'mobileAppsAndDesktopClients')
    }
    grantControls = @{
        operator = 'OR'
        termsOfUse = @('<agreement-id>')
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' \
  -Body $caPolicy -ContentType 'application/json'

# Create a CA policy in Report-Only mode to measure ToU impact
$reportOnly = @{
    displayName = '[REPORT-ONLY] Guest ToU requirement'
    state       = 'enabledForReportingButNotEnforcing'
    conditions  = @{
        users = @{
            includeGuestsOrExternalUsers = @{
                guestOrExternalUserTypes = 'b2bCollaborationGuest'
                externalTenants = @{ membershipKind = 'all' }
            }
        }
        applications = @{ includeApplications = @('All') }
        clientAppTypes = @('browser', 'mobileAppsAndDesktopClients')
    }
    grantControls = @{
        operator = 'OR'
        termsOfUse = @('<agreement-id>')
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' \
  -Body $reportOnly -ContentType 'application/json'

